import Button from "@/components/Button/Button";
import { InputField } from "@/components/Form/InputField";
import AdminLayout from "@/components/Layout/AdminLayout";
import Table from "@/components/Table/Table";
import { apiBaseUrl } from "@/config";
import { OriginAddress } from "@/types";
import { limit } from "@/lib/limitShowedData";
import axios from "axios";
import Link from "next/link";
import React, { useEffect, useState } from "react";
import { useRouter } from "next/router";
import { Toaster, toast } from "sonner";
import Modal from "@/components/Modal/Modal";
import { useCustomSWR } from "@/hooks/useCustomSWR";

type TDeleteAddress = {
  addressName: string;
  addressId: number;
};

const ManageAddress = () => {
  const [searchInput, setSearchInput] = useState<string>("");
  const [page, setPage] = useState<number>(0);
  const [activePage, setActivePage] = useState<number>(0);
  const [totalPage, setTotalPage] = useState<number>(0);
  const [arrPage, setArrPage] = useState<number[]>([]);
  const [orderBy, setOrderBy] = useState<"asc" | "desc">("asc");
  const [originAddressState, setOriginAddressState] = useState<OriginAddress[]>(
    []
  );
  const [prevAddressData, setPrevAddressData] = useState<OriginAddress[]>([]);
  const [isModalOpen, setIsModalOpen] = useState<boolean>(false);
  const [deletedAddress, setDeletedAddress] = useState<TDeleteAddress>({
    addressName: "",
    addressId: 0,
  });
  const router = useRouter();

  const deleteAddress = async (addressId: number) => {
    const response = await axios.delete(
      `${apiBaseUrl}/originAddress/${addressId}`
    );
    toast.success("Delete Successfull");
    return response.data;
  };

  const originAddress = useCustomSWR<OriginAddress[]>(
    `${apiBaseUrl}/originAddress`
  );

  const handleDelete = async (addressId: number) => {
    await deleteAddress(addressId);
    setIsModalOpen(false);
    originAddress.mutate();
  };

  const handleOpenModal = (deletedAddress: TDeleteAddress) => {
    setIsModalOpen(true);
    setDeletedAddress(deletedAddress);
  };

  const handleOnSearch = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setPage(0);
    setActivePage(0);
    setSearchInput(value);
    if (originAddressState) {
      const result = originAddressState.filter((address) =>
        address.addressName.toLocaleLowerCase().includes(value.toLowerCase())
      );
      setOriginAddressState(result);
    }

    if (value === "") {
      setOriginAddressState(prevAddressData);
    }
  };

  const handleGoToFirstPage = () => {
    setPage(0);
    setActivePage(0);
  };

  const handleGoToLastPage = () => {
    if (totalPage != 0) {
      setPage(totalPage - 1);
      setActivePage(totalPage - 1);
    }
  };

  const handleNextPage = () => {
    if (page != totalPage - 1) {
      setPage(page + 1);
      setActivePage(activePage + 1);
    }
  };

  const handlePrevPage = () => {
    if (page != 0) {
      setPage(page - 1);
      setActivePage(activePage - 1);
    }
  };

  const handleNumPage = (idx: number) => {
    setPage(idx);
    setActivePage(idx);
  };

  const compareCity = (a: OriginAddress, b: OriginAddress) => {
    if (a.city < b.city) {
      return -1;
    }

    if (a.city > b.city) {
      return 1;
    }

    return 0;
  };

  const handleOnSortCity = () => {
    if (orderBy === "asc") {
      originAddressState.sort(compareCity);
      setOrderBy("desc");
    } else {
      originAddressState.sort(compareCity).reverse();
      setOrderBy("asc");
    }
  };

  useEffect(() => {
    let total = 0;
    if (originAddressState) {
      total = originAddressState.length;
      setTotalPage(Math.ceil(total / limit));
    }
  }, [originAddressState]);

  useEffect(() => {
    let numArr = [];
    for (let i = 0; i < totalPage; i++) {
      numArr.push(i + 1);
    }
    setArrPage(numArr);
  }, [totalPage]);

  useEffect(() => {
    if (originAddress.data) {
      setOriginAddressState(originAddress.data);
      setPrevAddressData(originAddress.data);
    }
  }, [originAddress.data]);

  return (
    <>
      {isModalOpen && (
        <Modal
          addressName={deletedAddress.addressName}
          setIsOpen={setIsModalOpen}
          onHandleDelete={() => handleDelete(deletedAddress.addressId)}
        />
      )}
      <AdminLayout>
        <Toaster position="top-center" richColors />
        <h1 className="uppercase font-semibold text-2xl text-black pt-14">
          Manage Address List
        </h1>
        <div className="mt-5 flex flex-col">
          <div className="w-full flex justify-end items-center gap-4">
            <div>
              <Button
                variants="primarySmall"
                onClick={() => router.push("/admin/address/addAddress")}
              >
                Add Address
              </Button>
            </div>
            {/* <div className="w-72">
              <InputField
                type="text"
                name="filter"
                variants="small"
                placeholder="Search by name"
                value={searchInput}
                onChange={handleOnSearch}
                err=""
              />
            </div> */}
          </div>
          {originAddress.error && (
            <p className="text-black">
              Something went wrong, please refresh the page
            </p>
          )}
          {originAddress.isLoading ? (
            <div className="w-full flex justify-center">
              <span className="loading loading-spinner loading-md"></span>
            </div>
          ) : (
            originAddress && (
              <Table
                tableHeads={["Name", "City", "Province", "Street"]}
                isHeadAbleToSort={[false, true, false, false]}
                onClickHead={[
                  () => null,
                  () => handleOnSortCity(),
                  () => null,
                  () => null,
                ]}
              >
                {originAddressState
                  .slice(limit * page, limit * (page + 1))
                  .map((address) => (
                    <tr key={address.id}>
                      <td>{address.addressName}</td>
                      <td>{address.city}</td>
                      <td>{address.province}</td>
                      <td>{address.street}</td>
                      <td>
                        <div className="flex gap-2 items-center">
                          <Link
                            href={`/admin/address/${address.id}/editAddress`}
                            className="text-primary"
                          >
                            Edit
                          </Link>
                          <button
                            className="text-red-500"
                            onClick={() =>
                              address.id &&
                              handleOpenModal({
                                addressId: address.id,
                                addressName: address.addressName,
                              })
                            }
                          >
                            Delete
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                <tr></tr>
              </Table>
            )
          )}

          <div className="flex justify-end mt-4">
            <div className="flex gap-1">
              <div className="w-10">
                <Button onClick={handleGoToFirstPage}>{`<<`}</Button>
              </div>
              <div className="w-10">
                <Button onClick={handlePrevPage}>{`<`}</Button>
              </div>
              {arrPage.map((numPage, idx) => (
                <div className="w-10" key={idx}>
                  <Button
                    variants={activePage === idx ? "active" : ""}
                    onClick={() => handleNumPage(idx)}
                  >
                    {numPage}
                  </Button>
                </div>
              ))}
              <div className="w-10">
                <Button onClick={handleNextPage}>{`>`}</Button>
              </div>
              <div className="w-10">
                <Button onClick={handleGoToLastPage}>{`>>`}</Button>
              </div>
            </div>
          </div>
        </div>
      </AdminLayout>
    </>
  );
};

export default ManageAddress;
